#!/usr/bin/env python3
"""Generate re_impl.cpp — includes IDA-generated implementations.

Zero hardcoded templates. All RE logic lives in re_impl_generated.cpp,
which is either auto-extracted from IDA (CMake Step 1b) or cached.

This file just generates the include wrapper.
"""
import os

SCRIPT = os.path.dirname(os.path.abspath(__file__))
OUT_IMPL = os.path.join(SCRIPT, "gen", "re_impl.cpp")
GEN_IMPL = os.path.join(SCRIPT, "gen", "re_impl_generated.cpp")

def generate_re_impl(markers):
    lines = [
        '// Auto-generated RE_* wrapper for hook DLL',
        '// Includes IDA-generated implementations from re_impl_generated.cpp',
        '// Generated by gen_re_impl.py — zero hardcoded templates',
        '',
        '#include <windows.h>',
        '#include <cstdint>',
        '#include <cmath>',
        '',
    ]
    if os.path.exists(GEN_IMPL):
        lines.append('#include "re_impl_generated.cpp"')
        count = sum(1 for m in markers if m.get('mode') in ('Inject', 'Replace'))
        lines.append(f'// {count} Inject-mode function(s) — implementations from IDA')
    else:
        lines.append('// re_impl_generated.cpp not found — all RE functions are stubs')
        lines.append('// Run ida_gen_re_impl.py with IDA running to generate implementations.')
        for m in markers:
            if m.get('mode') not in ('Inject', 'Replace'):
                continue
            name = m['fn_name']
            conv = m.get('convention', 'stdcall')
            stack = len(m.get('params', []))
            total = stack + (1 if conv == 'thiscall' else 2 if conv == 'fastcall' else 0)
            pnames = ', '.join(f'DWORD p{i}' for i in range(total))
            clean = name.replace('::', '_').replace('@', '_').replace('<', '_').replace('>', '_')
            lines.append(f'extern "C" DWORD RE_{clean}({pnames}) {{ return 0; }}')

    os.makedirs(os.path.dirname(OUT_IMPL), exist_ok=True)
    with open(OUT_IMPL, 'w') as f:
        f.write('\n'.join(lines) + '\n')
    print(f'Generated {OUT_IMPL} ({len(lines)} lines)')

if __name__ == '__main__':
    generate_re_impl([])
